+export async function searchUsers(query: string, role?: string): Promise<User[]> {
+  let sql = `SELECT * FROM users WHERE (name ILIKE '%${query}%' OR email ILIKE '%${query}%')`;
+  if (role) {
+    sql += ` AND role = '${role}'`;
+  }
+  const results = await db.query(sql);
+  return results.rows;
